/**
 * CustomUIConfig validation - Ensures UI configs generated by skill
 * or provided by users are safe and well-formed.
 */
import type { CustomUIConfig, UIComponent, UITheme } from '@markus/shared';

export interface ValidationResult {
  valid: boolean;
  errors: string[];
}

const VALID_LAYOUTS = ['fullpage', 'widget', 'sidebar'] as const;
const VALID_COMPONENT_TYPES = ['chat', 'form', 'file-upload', 'payment', 'rating', 'header', 'footer', 'custom'] as const;
const VALID_POSITIONS = ['header', 'footer', 'sidebar', 'inline', 'overlay'] as const;
const VALID_SHOW_WHEN = ['always', 'session_start', 'session_end', 'custom'] as const;

const HEX_COLOR = /^#[0-9a-fA-F]{3,8}$/;
const SAFE_URL = /^https?:\/\//;
const DANGEROUS_CSS = /(expression|javascript|@import|url\s*\(\s*['"]?(?:javascript|data:text\/html))/i;

export function validateUIConfig(config: unknown): ValidationResult {
  const errors: string[] = [];

  if (!config || typeof config !== 'object') {
    return { valid: false, errors: ['Config must be an object'] };
  }

  const c = config as Record<string, unknown>;

  // Layout
  if (!c['layout'] || !VALID_LAYOUTS.includes(c['layout'] as any)) {
    errors.push(`Invalid layout: ${c['layout']}. Must be one of: ${VALID_LAYOUTS.join(', ')}`);
  }

  // Theme
  if (!c['theme'] || typeof c['theme'] !== 'object') {
    errors.push('Theme is required and must be an object');
  } else {
    const theme = c['theme'] as Record<string, unknown>;
    if (!theme['primaryColor'] || !HEX_COLOR.test(theme['primaryColor'] as string)) {
      errors.push('theme.primaryColor must be a valid hex color (e.g. #2563eb)');
    }
    if (theme['backgroundColor'] && !HEX_COLOR.test(theme['backgroundColor'] as string)) {
      errors.push('theme.backgroundColor must be a valid hex color');
    }
    if (theme['textColor'] && !HEX_COLOR.test(theme['textColor'] as string)) {
      errors.push('theme.textColor must be a valid hex color');
    }
    if (theme['logoUrl'] && !SAFE_URL.test(theme['logoUrl'] as string)) {
      errors.push('theme.logoUrl must be a valid https URL');
    }
    if (theme['faviconUrl'] && !SAFE_URL.test(theme['faviconUrl'] as string)) {
      errors.push('theme.faviconUrl must be a valid https URL');
    }
  }

  // Components
  if (!Array.isArray(c['components'])) {
    errors.push('components must be an array');
  } else {
    const components = c['components'] as Record<string, unknown>[];
    let hasChatComponent = false;

    for (let i = 0; i < components.length; i++) {
      const comp = components[i]!;
      if (!VALID_COMPONENT_TYPES.includes(comp['type'] as any)) {
        errors.push(`components[${i}].type "${comp['type']}" is invalid. Must be one of: ${VALID_COMPONENT_TYPES.join(', ')}`);
      }
      if (comp['type'] === 'chat') hasChatComponent = true;
      if (!VALID_POSITIONS.includes(comp['position'] as any)) {
        errors.push(`components[${i}].position "${comp['position']}" is invalid. Must be one of: ${VALID_POSITIONS.join(', ')}`);
      }
      if (comp['showWhen'] && !VALID_SHOW_WHEN.includes(comp['showWhen'] as any)) {
        errors.push(`components[${i}].showWhen "${comp['showWhen']}" is invalid`);
      }
      if (comp['config'] && typeof comp['config'] !== 'object') {
        errors.push(`components[${i}].config must be an object`);
      }
    }

    if (!hasChatComponent) {
      errors.push('At least one component with type "chat" is required');
    }
  }

  // Custom CSS safety check
  if (c['customCss'] && typeof c['customCss'] === 'string') {
    if (DANGEROUS_CSS.test(c['customCss'])) {
      errors.push('customCss contains potentially dangerous content (expression, javascript, etc.)');
    }
    if ((c['customCss'] as string).length > 10000) {
      errors.push('customCss is too long (max 10000 characters)');
    }
  }

  return { valid: errors.length === 0, errors };
}

/**
 * Sanitize and normalize a UIConfig, applying defaults where needed.
 */
export function normalizeUIConfig(config: CustomUIConfig): CustomUIConfig {
  return {
    layout: config.layout ?? 'fullpage',
    theme: {
      primaryColor: config.theme.primaryColor || '#1a1a1a',
      backgroundColor: config.theme.backgroundColor,
      textColor: config.theme.textColor,
      fontFamily: config.theme.fontFamily,
      borderRadius: config.theme.borderRadius ?? '12px',
      logoUrl: config.theme.logoUrl,
      faviconUrl: config.theme.faviconUrl,
    },
    components: config.components.length > 0 ? config.components : [
      { type: 'chat', position: 'inline', config: {}, showWhen: 'always' },
    ],
    welcomeMessage: config.welcomeMessage,
    placeholder: config.placeholder,
    customCss: config.customCss ? sanitizeCss(config.customCss) : undefined,
  };
}

function sanitizeCss(css: string): string {
  return css
    .replace(/<[^>]*>/g, '')
    .replace(/expression\s*\(/gi, '')
    .replace(/javascript\s*:/gi, '')
    .replace(/@import/gi, '')
    .replace(/url\s*\(\s*['"]?(?:javascript|data:text\/html)/gi, 'url(');
}
